// Time:  O(n)
// Space: O(1)

class Solution {
public:
    string largestOddNumber(string num) {
        for (int i = size(num) - 1; i >= 0; --i) {
            if ((num[i] - '0') % 2) {
                return num.substr(0, i + 1);
            }
        }
        return "";
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def largestOddNumber(self, num):
        """
        :type num: str
        :rtype: str
        """
        for i in reversed(xrange(len(num))):
            if int(num[i])%2:
                return num[:i+1]
        return ""
